/**
 * pnpm hoists @prisma/client with a stale .prisma/client (no Product.expiryDate).
 * After generate, copy the fresh client from apps/api into every pnpm @prisma+client copy.
 */
const fs = require("fs");
const path = require("path");

const repoRoot = path.join(__dirname, "../../..");
const source = path.join(repoRoot, "apps/api/node_modules/.prisma/client");

if (!fs.existsSync(source)) {
  console.warn("sync-prisma-client: source missing, run prisma generate first.");
  process.exit(0);
}

const pnpmDir = path.join(repoRoot, "node_modules/.pnpm");
if (!fs.existsSync(pnpmDir)) {
  console.warn("sync-prisma-client: no .pnpm directory, skipping.");
  process.exit(0);
}

let synced = 0;
for (const entry of fs.readdirSync(pnpmDir)) {
  if (!entry.startsWith("@prisma+client@")) {
    continue;
  }
  const target = path.join(pnpmDir, entry, "node_modules/.prisma/client");
  if (!fs.existsSync(path.dirname(target))) {
    continue;
  }
  fs.rmSync(target, { recursive: true, force: true });
  fs.cpSync(source, target, { recursive: true });
  synced += 1;
}

console.log(`sync-prisma-client: updated ${synced} pnpm @prisma/client copy(ies).`);
